@page "/chat"
@layout ChatLayout
@using sv_5a3876b07aba4e339e1a63d6c97fe4ce.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<!-- ============ LEFT SIDEBAR — Channel List ============ -->
<aside class="channel-sidebar">
    <div class="sidebar-header">
        <h4>Channels</h4>
    </div>
    <ul class="channel-list">
        @if (_channels is not null)
        {
            @foreach (var channel in _channels)
            {
                <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-name"># @channel.Name</div>
                    <div class="channel-desc">@Truncate(channel.Description, 40)</div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </li>
            }
        }
    </ul>
</aside>

<!-- ============ MAIN MESSAGE AREA ============ -->
<section class="message-area @(_threadOpen ? "thread-open" : "")">
    @if (_activeChannel is not null)
    {
        <div class="message-header">
            <h5># @_activeChannel.Name</h5>
            <span class="message-header-desc">@_activeChannel.Description</span>
        </div>

        <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
            @if (_loadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @if (_messages is not null)
            {
                @foreach (var msg in _messages)
                {
                    <div class="message-row" @onmouseover="() => _hoveredMessageId = msg.Id"
                         @onmouseout="() => { if (_hoveredMessageId == msg.Id) _hoveredMessageId = null; }">
                        <div class="message-bubble">
                            <div class="message-meta">
                                <span class="message-author">@msg.Author</span>
                                <span class="message-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-content">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @{ var threadInfo = GetThreadSummary(msg.Id); }
                            @if (threadInfo is not null)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @threadInfo.ReplyCount @(threadInfo.ReplyCount == 1 ? "reply" : "replies")
                                </button>
                            }
                        </div>

                        @if (_hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" title="Reply in thread"
                                        @onclick="() => OpenThreadAsync(msg)">💬 Reply</button>
                                <button class="action-btn" title="Add reaction"
                                        @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                            </div>
                            @if (_emojiPickerMessageId == msg.Id)
                            {
                                <div class="emoji-picker">
                                    @foreach (var emoji in _commonEmojis)
                                    {
                                        <button class="emoji-btn" @onclick="() => ReactAsync(msg.Id, emoji)">@emoji</button>
                                    }
                                </div>
                            }
                        }
                    </div>
                }
            }
        </div>

        <div class="message-input-area">
            <textarea @bind="_newMessage" @bind:event="oninput"
                      placeholder="Message #@_activeChannel.Name"
                      @onkeydown="OnMainKeyDown" rows="1"></textarea>
            <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_newMessage)"
                    @onclick="SendMainMessageAsync">Send</button>
        </div>
    }
    else
    {
        <div class="no-channel-selected">
            <p>Select a channel to start chatting</p>
        </div>
    }
</section>

<!-- ============ RIGHT PANEL — Thread View ============ -->
@if (_threadOpen && _threadRootMessage is not null)
{
    <aside class="thread-panel">
        <div class="thread-header">
            <h5>Thread</h5>
            <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
        </div>
        <div class="thread-root-quote">
            <span class="message-author">@_threadRootMessage.Author</span>
            <span class="message-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
            <div class="message-content">@_threadRootMessage.Content</div>
        </div>
        <div class="thread-replies" @ref="_threadListRef">
            @if (_threadReplies is not null)
            {
                @foreach (var reply in _threadReplies)
                {
                    <div class="message-bubble">
                        <div class="message-meta">
                            <span class="message-author">@reply.Author</span>
                            <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                        </div>
                        <div class="message-content">@reply.Content</div>
                        @if (reply.Reactions.Count > 0)
                        {
                            <div class="reaction-row">
                                @foreach (var r in reply.Reactions)
                                {
                                    <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                            @onclick="() => ReactAsync(reply.Id, r.Emoji)">
                                        @r.Emoji @r.Users.Count
                                    </button>
                                }
                            </div>
                        }
                    </div>
                }
            }
        </div>
        <div class="message-input-area">
            <textarea @bind="_threadReply" @bind:event="oninput"
                      placeholder="Reply…"
                      @onkeydown="OnThreadKeyDown" rows="1"></textarea>
            <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_threadReply)"
                    @onclick="SendThreadReplyAsync">Reply</button>
        </div>
    </aside>
}

@code {
    private const int PageSize = 30;

    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;

    private List<Message>? _messages;
    private int _skip;
    private bool _loadingMore;
    private bool _allLoaded;

    private string _newMessage = "";
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private string _threadReply = "";

    // Thread summaries keyed by root message id
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    private ElementReference _messageListRef;
    private ElementReference _threadListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _skip = 0;
        _allLoaded = false;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _skip = _messages.Count;
        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);
        await RefreshChannelUnread(channel);
    }

    private async Task RefreshChannelUnread(Channel channel)
    {
        var updated = await ChatService.GetChannelsAsync();
        _channels = updated;
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_loadingMore || _allLoaded || _activeChannelId is null) return;
        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count == 0)
        {
            _allLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _skip += older.Count;
            BuildThreadSummaries();
        }
        _loadingMore = false;
    }

    private void BuildThreadSummaries()
    {
        if (_messages is null) return;
        _threadSummaries.Clear();

        var repliesByRoot = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value);

        foreach (var group in repliesByRoot)
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }

    private ThreadSummary? GetThreadSummary(int messageId)
    {
        _threadSummaries.TryGetValue(messageId, out var summary);
        return summary;
    }

    private async Task SendMainMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
        _messages ??= [];
        _messages.Add(sent);
        _newMessage = "";
        await ScrollToBottom(_messageListRef);
    }

    private async Task OnMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMainMessageAsync();
        }
    }

    // --- Reactions ---

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh the message list to reflect the new reaction
        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _skip > 0 ? _skip : PageSize);
        }

        // Also refresh thread if open
        if (_threadOpen && _threadRootMessage is not null)
        {
            _threadReplies = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    // --- Thread ---

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadReply = "";
        _threadOpen = true;
        _emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
        _threadReply = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReply) || _threadRootMessage is null || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReply.Trim(), _threadRootMessage.Id);
        _threadReplies ??= [];
        _threadReplies.Add(sent);
        _threadReply = "";

        // Also add to main list and refresh summaries
        _messages ??= [];
        _messages.Add(sent);
        BuildThreadSummaries();
        await ScrollToBottom(_threadListRef);
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // --- Scrolling ---

    private async Task OnMessageListScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("chatInterop.getScrollTop", _messageListRef);
        if (scrollTop < 50)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task ScrollToBottom(ElementReference element)
    {
        try
        {
            await JS.InvokeVoidAsync("chatInterop.scrollToBottom", element);
        }
        catch (JSException)
        {
            // Element may not be rendered yet
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await ScrollToBottom(_messageListRef);
        }
    }

    // --- Helpers ---

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..(maxLength - 1)] + "…";
}

